effect.shader:
#define OUTLINE_BIAS -.5
#define OUTLINE_POWER 1.
#define PRECISION 6.

void main()
{
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec4 p = pow(texColor, vec4(2.2));
    vec4 s = pow(texture2DCv(inputImg.texture, acScreenNorm + vec2(0.5, 0.5) / acScreenSize), vec4(2.2));
    float l = clamp(pow(length(p-s),OUTLINE_POWER)*strength+OUTLINE_BIAS,0.,1.);
    p = floor(pow(p,vec4(1./2.2))*(PRECISION+.999))/PRECISION;
    vec4 outColor = mix(p,outline_color,l);
    gl_FragColor = vec4(outColor.rgb,texColor.a);
}
